import{_ as s,o as r,c as e,ag as t}from"./chunks/framework.WmBmIPw-.js";const _=JSON.parse('{"title":"变邻域搜索（Variable Neighborhood Search, VNS）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/vns.md","filePath":"or-opt/vns.md","lastUpdated":1777185397000}'),o={name:"or-opt/vns.md"};function n(h,a,i,l,k,p){return r(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="变邻域搜索-variable-neighborhood-search-vns" tabindex="-1">变邻域搜索（Variable Neighborhood Search, VNS） <a class="header-anchor" href="#变邻域搜索-variable-neighborhood-search-vns" aria-label="Permalink to &quot;变邻域搜索（Variable Neighborhood Search, VNS）&quot;">​</a></h1><p>变邻域搜索由 Mladenović 与 Hansen 等系统化提出：在单点搜索框架下，预备一组由弱到强（或由近到远）的邻域结构，在局部最优处通过「换邻域」或「抖动 + 再局部搜索」跳出当前吸引域。与固定单邻域的下降法相比，显式利用多邻域的互补性，属单解、基于邻域的元启发式，见 <a href="./metaheuristics.html">元启发式总览</a>。</p><p><strong>适用</strong>：组合优化（路径、调度、划分等）与部分连续问题在能定义多个邻域算子且每步评价 f 可承受时；邻域设计对效果起决定作用。</p><p><strong>核心</strong>：最外层是「设邻域下标 k → 抖 → 局部搜 → 按结果改 k/当前解」的循环。本页先说明记号、抖动、变邻域下降（VND）子过程，再收拢关键要素，再给出基本 VNS 主循环的示意框。抖动与 VND 的语义在各自小节中展开，主循环框中第 3、4 步与之一致。</p><hr><h2 id="记号与邻域结构" tabindex="-1">记号与邻域结构 <a class="header-anchor" href="#记号与邻域结构" aria-label="Permalink to &quot;记号与邻域结构&quot;">​</a></h2><p>设目标 f(s) 最小化，s 为可行解。给定有限个邻域映射 N_k，k∈{1,…,K_max}，通常按「步幅」或「破坏程度」单调：N_1 最局部，N_Kmax 扰动最大。对点 s，N_k(s) 表示经第 k 类算子一步可达的邻域点集（实现上常从 N_k(s) 中采样或枚举子集）。外层<strong>抖动</strong>用的 k 与<strong>内层 VND</strong> 在邻域族 1,…,K 上切换的 k 是两套逻辑，在代码中建议用不同变量名表示，免混淆。</p><hr><h2 id="抖动-shaking" tabindex="-1">抖动（Shaking） <a class="header-anchor" href="#抖动-shaking" aria-label="Permalink to &quot;抖动（Shaking）&quot;">​</a></h2><p><strong>作用</strong>：当当前 s 在某一局部搜索下已是局优时，若只在同一套确定性邻域里下降，会反复落回同一片吸引域。抖动的目标不是让单步 f 变小，而是利用随机性从 N_k(s) 里取新起点 s′，使随后的局部搜索有机会进入新的谷地。s′ 可以明显劣于 s，也无需在 N_k 上对 f 做任何最优化；这与 VND 在 N_k 内「找改进步」的取向相反。</p><p><strong>与邻域下标 k 的关系</strong>：k 标定「这一次抖动用哪一级邻域算子/步幅」。常令 k 自 1 递增至 K_max。k 较小时，一步只离开 s 的邻近位置，多在同一盆地内换起点；k 较大时，一步跨越更远、更易破坏当前结构，因而更常配合修复算子，并依赖其后的 VND/下降把 s′ 收敛到新的局优。</p><p><strong>从 N_k(s) 中生成 s′ 的常见方式</strong>（实现上可择一或组合）：</p><ul><li>一步随机邻居：在 N_k(s) 的枚举/候选集合中等概率或加权抽一点。</li><li>多步随机游走：对固定 k 连续做 t 次「在 N_k 中抽随机邻步并前进一步」，t 可常数、与 k 成比例或上界内均匀随机，相当于用同一 N_k 工具堆出更强扰动而不另建一套邻域结构。</li><li>逆移与有偏：若仅防「立刻逆回上一步」即可减轻短循环，可与极轻量禁忌同用；若引入复杂记忆则更接近混合 TS，已超出「纯 VNS 抖动」的朴素表述，实现时需单独定稿。</li></ul><p><strong>可行性与修复</strong>：N_k 可能产生不可行 s′ 时，可丢弃后重试、在 N_k 上有限次重采样，或调问题相关修复把 s′ 投回可行集；再进入局部搜索。哪一级邻域易不可行、修复代价多大，是邻域设计的一部分。</p><p><strong>何时加大 k</strong>：若多次记录「在 VND/局搜后仍不优于当前 s」，则把 k 加一，使下一次在更大 N_k 上抽 s′。语义上等价于小抖不动就强抖，而不同于把每次搜索都变成单次全局大扰动后重启；层次化 k 是 VNS 的典型特征。</p><p><strong>与内层局搜的分工</strong>：抖动只负责把点扔到新区域，内层局搜把新起点收敛到其邻域极值。重复「抖—搜」在随机性上比单邻域上长链随机可接受非改进步更短、也更容易控计算量，坏起点不必沿轨迹长滚，可再进入对 k 与 s 的更新。</p><hr><h2 id="变邻域下降-vnd" tabindex="-1">变邻域下降（VND） <a class="header-anchor" href="#变邻域下降-vnd" aria-label="Permalink to &quot;变邻域下降（VND）&quot;">​</a></h2><p><strong>定位</strong>：在基本 VNS 的局部搜一步中，常采用下框的 VND。在同一套多邻域 N_1,…,N_K 上做无随机、确定性从细到粗切换，直到各邻域上均为局优。VND 只做局部最优传递；外层控制抖动的下标与内层 VND 的邻域下标实现处宜分开，勿与基本 VNS 最外层的 k 混写。</p><p>VND 仍可能停在多邻域意义下的强局优，那时需要靠再抖动换起点，而不是在 VND 里无限加邻域。</p><p>在基本 VNS 中，VND 的输入 s 是抖动所得到的 s′，输出 s″ 再参与最外层的接受与 k 的更新。下框从任意可行 s 起算；接入基本 VNS 时，s 取抖动点。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 变邻域下降 VND</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>选定可行解 s，设 k ← 1。</p><h3 id="_2-在当前邻域内找改进" tabindex="-1">2. 在当前邻域内找改进 <a class="header-anchor" href="#_2-在当前邻域内找改进" aria-label="Permalink to &quot;2. 在当前邻域内找改进&quot;">​</a></h3><p>在 N_k(s) 中寻找使 f 下降的点 s′（依「首次改进」「最速下降」等规则，直到 N_k 内对 s 为局部最优）。</p><h3 id="_3-邻域切换" tabindex="-1">3. 邻域切换 <a class="header-anchor" href="#_3-邻域切换" aria-label="Permalink to &quot;3. 邻域切换&quot;">​</a></h3><p>若找到改进 s′，令 s ← s′，k ← 1（回到最细邻域继续）；若 N_k 内无改进，令 k ← k+1。</p><h3 id="_4-终止" tabindex="-1">4. 终止 <a class="header-anchor" href="#_4-终止" aria-label="Permalink to &quot;4. 终止&quot;">​</a></h3><p>若 k&gt;K（所有 N_k 对当前 s 均局部最优），停，输出 s；否则回到步骤 2。</p></div><hr><h2 id="关键要素" tabindex="-1">关键要素 <a class="header-anchor" href="#关键要素" aria-label="Permalink to &quot;关键要素&quot;">​</a></h2><p><strong>邻域族顺序</strong>：k 小对应小扰动、利于微调；k 大利于跳出，但过强抖动易损可行或需修复算子。实践上常问题特化设计多种 2-opt、insert、swapping、大规模破坏—修复等，并在 N_k 间保持可实现的评价代价。抖动、VND 中 k 的语义见上两节。</p><p><strong>与禁忌搜索、模拟退火</strong>：VNS 用多邻域结构 + 显式改变抖动范围管理探索，不必依赖禁忌表或温度；也可与 TS/SA 混合。</p><p><strong>扩展</strong>：如简化 VNS、并行 VNS、与精确子程序衔接等，属文献变体，本页不逐条列参。</p><hr><h2 id="主循环-基本-vns-最小化示意" tabindex="-1">主循环（基本 VNS，最小化示意） <a class="header-anchor" href="#主循环-基本-vns-最小化示意" aria-label="Permalink to &quot;主循环（基本 VNS，最小化示意）&quot;">​</a></h2><p>最外层在做什么，由下框给出。第 3 步的抖动、第 4 步的局部搜，与上文「抖动（Shaking）」「变邻域下降（VND）」两节同义。第 4 步以 VND 为默认，也可换为其他多邻域或单邻域下降。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 基本 VNS（单解、多邻域 + 抖动）</p><h3 id="_1-初始化-1" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化-1" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>生成初始解 s，记历史最优 s⋆ ← s。设邻域族 N_1,…,N_K 与最大抖动强度 K_max。内层局搜的体例以第三节的 VND 为默认理解。</p><h3 id="_2-外层邻域下标" tabindex="-1">2. 外层邻域下标 <a class="header-anchor" href="#_2-外层邻域下标" aria-label="Permalink to &quot;2. 外层邻域下标&quot;">​</a></h3><p>设 k ← 1，表示本回合抖动使用的邻域级别。</p><h3 id="_3-抖动" tabindex="-1">3. 抖动 <a class="header-anchor" href="#_3-抖动" aria-label="Permalink to &quot;3. 抖动&quot;">​</a></h3><p>在 N_k 上自 s 依随机规则得新起点 s′（见上文「抖动（Shaking）」）。</p><h3 id="_4-局部搜索" tabindex="-1">4. 局部搜索 <a class="header-anchor" href="#_4-局部搜索" aria-label="Permalink to &quot;4. 局部搜索&quot;">​</a></h3><p>以 s′ 为起点在全部或部分邻域上下降，直至得局部最优点 s″；默认用上文「变邻域下降（VND）」；也可换用其他多邻域或单邻域下降。</p><h3 id="_5-接受与邻域级更新" tabindex="-1">5. 接受与邻域级更新 <a class="header-anchor" href="#_5-接受与邻域级更新" aria-label="Permalink to &quot;5. 接受与邻域级更新&quot;">​</a></h3><p>若 f(s″)&lt;f(s)，令 s ← s″，k ← 1，若 f(s″)&lt;f(s⋆) 则 s⋆ ← s″；否则 k ← k+1。若 k&gt;K_max，可 k ← 1 并配合全局迭代上限或 s ← s″ 的变体，依实现定稿。</p><h3 id="_6-终止" tabindex="-1">6. 终止 <a class="header-anchor" href="#_6-终止" aria-label="Permalink to &quot;6. 终止&quot;">​</a></h3><p>达时间、总评价次数、连续无改进步数等，输出 s⋆。</p></div>',31)])])}const N=s(o,[["render",n]]);export{_ as __pageData,N as default};
